AMC8_UNITS =  [{'name': '数的运算', 'description': '掌握整数、分数、小数、百分数的基本运算和巧算技巧', 'sort_order': 1, 'lessons': [{'title': '整数四则运算', 'lesson_type': 'interactive', 'estimated_minutes': 25, 'sort_order': 1, 'is_published': True, 'content': {'sections': [{'type': 'introduction', 'content': '整数四则运算是所有数学的基础。在AMC 8中，约30%的题目涉及整数运算，掌握好这一章对拿分至关重要！'}, {'type': 'concept', 'title': '运算优先级', 'content': '牢记 PEMDAS 运算顺序：括号(Parentheses) > 指数(Exponents) > 乘除(Multiplication/Division) > 加减(Addition/Subtraction)。注意乘除同级从左到右，加减同级从左到右。'}, {'type': 'example', 'problem': '计算：6 + 2 × (3² - 4) ÷ 2', 'solution': '先算括号内：3² = 9, 9 - 4 = 5\n然后：2 × 5 = 10\n然后：10 ÷ 2 = 5\n最后：6 + 5 = 11'}, {'type': 'example', 'problem': 'AMC 8真题：计算 1 + 2 + 3 + ... + 100 的值', 'solution': '等差数列求和公式：S = n(a₁ + aₙ)/2\nS = 100 × (1 + 100)/2 = 100 × 101/2 = 5050'}, {'type': 'practice', 'problems': [{'question': '计算 15 - 3 × (2 + 4)', 'options': ['-3', '3', '27', '-15'], 'answer': '-3'}, {'question': '计算 2³ + 4² - 5', 'options': ['19', '13', '17', '23'], 'answer': '19'}, {'question': '从1到50的所有偶数的和是多少？', 'options': ['650', '625', '1275', '600'], 'answer': '650'}]}, {'type': 'summary', 'content': '整数运算的关键：注意运算顺序，善用结合律和分配律简化计算。等差数列求和是AMC 8的常考题型！'}]}}, {'title': '分数运算', 'lesson_type': 'interactive', 'estimated_minutes': 25, 'sort_order': 2, 'is_published': True, 'content': {'sections': [{'type': 'introduction', 'content': '分数运算是AMC 8的必考内容。掌握分数的加减乘除、通分和约分技巧，能帮你快速解题！'}, {'type': 'concept', 'title': '分数运算规则', 'content': '加法：先通分再相加。乘法：分子乘分子，分母乘分母。除法：除以一个分数等于乘以它的倒数。约分：找出分子分母的最大公约数(GCD)同时除以。'}, {'type': 'example', 'problem': '计算：3/4 + 5/6 - 1/3', 'solution': '通分：最小公倍数 = 12\n= 9/12 + 10/12 - 4/12\n= 15/12 = 5/4'}, {'type': 'example', 'problem': 'AMC 8真题：计算 (1/2 × 2/3) ÷ (1/4 × 4/5)', 'solution': '分子：1/2 × 2/3 = 1/3\n分母：1/4 × 4/5 = 1/5\n结果：1/3 ÷ 1/5 = 1/3 × 5 = 5/3'}, {'type': 'practice', 'problems': [{'question': '计算 7/12 + 5/8', 'options': ['29/24', '12/20', '35/96', '31/24'], 'answer': '29/24'}, {'question': '计算 3/5 × 10/9', 'options': ['2/3', '30/45', '6/5', '1/3'], 'answer': '2/3'}, {'question': '一桶油的3/8用掉后，又用掉剩下的1/3，还剩几分之几？', 'options': ['5/12', '1/2', '7/24', '5/18'], 'answer': '5/12'}]}, {'type': 'summary', 'content': '分数运算口诀：先看运算符，加减要通分，乘法直接乘，除法翻跟头。约分化简别忘了！'}]}}, {'title': '小数与百分数', 'lesson_type': 'interactive', 'estimated_minutes': 20, 'sort_order': 3, 'is_published': True, 'content': {'sections': [{'type': 'introduction', 'content': '小数和百分数在日常生活中非常常见，AMC 8也经常考查这部分内容。掌握小数、分数、百分数之间的转换是关键！'}, {'type': 'concept', 'title': '小数与百分数转换', 'content': '小数→百分数：乘以100加%。百分数→小数：去掉%除以100。分数→小数：分子÷分母。常用分数小数对照：1/4=0.25=25%, 1/5=0.2=20%, 3/8=0.375=37.5%'}, {'type': 'example', 'problem': '一件商品先涨价20%，再降价20%，最终价格与原价相比如何？', 'solution': '设原价100元\n涨价后：100 × 1.2 = 120元\n降价后：120 × 0.8 = 96元\n最终比原价便宜4%'}, {'type': 'example', 'problem': 'AMC 8真题：如果x是45的20%，y是60的30%，求x+y', 'solution': 'x = 45 × 0.2 = 9\ny = 60 × 0.3 = 18\nx + y = 27'}, {'type': 'practice', 'problems': [{'question': '0.375化成最简分数是多少？', 'options': ['3/8', '37/100', '375/1000', '7/20'], 'answer': '3/8'}, {'question': '某数增加25%后是75，原数是多少？', 'options': ['60', '56.25', '50', '100'], 'answer': '60'}, {'question': '一根绳子剪掉40%后剩3米，原长多少米？', 'options': ['5', '7.5', '4.2', '6'], 'answer': '5'}]}, {'type': 'summary', 'content': '百分数问题的关键：注意"增加了"和"增加到"的区别。原价×(1+增长率)=新价。连续增减不能直接相加！'}]}}, {'title': '估算与近似', 'lesson_type': 'interactive', 'estimated_minutes': 20, 'sort_order': 4, 'is_published': True, 'content': {'sections': [{'type': 'introduction', 'content': '估算是AMC 8的重要技能。有时不需要精确计算，通过合理的估算就能快速选出正确答案！'}, {'type': 'concept', 'title': '估算技巧', 'content': '① 四舍五入法：将数字近似到最近的整十、整百\n② 夹逼法：确定答案在两个边界之间\n③ 放缩法：适当放大或缩小来估计范围\n④ 首位估算法：只看最高位进行粗算'}, {'type': 'example', 'problem': '估算 497 × 203 的值最接近哪个？', 'solution': '497 ≈ 500, 203 ≈ 200\n500 × 200 = 100,000\n实际值 = 100,891，非常接近！'}, {'type': 'example', 'problem': 'AMC 8真题：1.23 × 4.56 最接近哪个整数？', 'solution': '1.23 ≈ 1.2, 4.56 ≈ 4.5\n1.2 × 4.5 = 5.4\n实际 = 5.6088，约等于6'}, {'type': 'practice', 'problems': [{'question': '估算 998 × 1003 最接近？', 'options': ['1000000', '999000', '1001000', '1010000'], 'answer': '1001000'}, {'question': '估算 √80 最接近哪个整数？', 'options': ['8', '9', '10', '7'], 'answer': '9'}, {'question': '1.9 × 2.1 × 3.05 的值最接近？', 'options': ['12', '10', '14', '8'], 'answer': '12'}]}, {'type': 'summary', 'content': '估算三步走：先简化数字 → 做基本运算 → 判断范围。AMC选择题中，估算往往比精确计算更快！'}]}}, {'title': '巧算与速算技巧', 'lesson_type': 'interactive', 'estimated_minutes': 25, 'sort_order': 5, 'is_published': True, 'content': {'sections': [{'type': 'introduction', 'content': '巧算是AMC竞赛的制胜法宝！学会运用运算律和特殊技巧，可以让复杂计算变得简单。'}, {'type': 'concept', 'title': '常用巧算方法', 'content': '① 凑整法：把数凑成10、100等整数\n② 提取公因数：ab + ac = a(b + c)\n③ 裂项相消：1/n(n+1) = 1/n - 1/(n+1)\n④ 补数法：999 = 1000 - 1，利用补数简化\n⑤ 平方差公式：a² - b² = (a+b)(a-b)'}, {'type': 'example', 'problem': '巧算：99 × 101', 'solution': '利用平方差公式：99 × 101 = (100-1)(100+1) = 100² - 1² = 9999'}, {'type': 'example', 'problem': '巧算：1/(1×2) + 1/(2×3) + 1/(3×4) + ... + 1/(99×100)', 'solution': '裂项：1/n(n+1) = 1/n - 1/(n+1)\n= (1-1/2) + (1/2-1/3) + ... + (1/99-1/100)\n= 1 - 1/100 = 99/100'}, {'type': 'practice', 'problems': [{'question': '巧算 98 × 102 的值', 'options': ['9996', '10000', '9998', '10004'], 'answer': '9996'}, {'question': '计算 125 × 32 × 25', 'options': ['100000', '98000', '102000', '96000'], 'answer': '100000'}, {'question': '巧算 999² = ?', 'options': ['998001', '999001', '999981', '1000001'], 'answer': '998001'}]}, {'type': 'summary', 'content': '巧算的核心思想：不硬算，找规律！凑整、裂项、公式，灵活运用能大幅提升解题速度。'}]}}]}, {'name': '代数基础', 'description': '学习方程、比例、函数初步和数列规律', 'sort_order': 2, 'lessons': [{'title': '一元一次方程', 'lesson_type': 'interactive', 'estimated_minutes': 25, 'sort_order': 1, 'is_published': True, 'content': {'sections': [{'type': 'introduction', 'content': '方程是代数的核心。AMC 8中，很多应用题都可以通过列方程来解决。掌握一元一次方程是学好代数的第一步！'}, {'type': 'concept', 'title': '解方程步骤', 'content': '① 去分母（等式两边同乘最小公倍数）\n② 去括号（分配律展开）\n③ 移项（把含未知数的项移到一边，常数项移到另一边）\n④ 合并同类项\n⑤ 系数化为1（两边同除以未知数的系数）'}, {'type': 'example', 'problem': '解方程：3(x - 2) + 5 = 2x + 7', 'solution': '展开：3x - 6 + 5 = 2x + 7\n化简：3x - 1 = 2x + 7\n移项：3x - 2x = 7 + 1\nx = 8'}, {'type': 'example', 'problem': 'AMC 8真题：小明有若干颗糖，给小红一半多1颗后还剩10颗，原来有多少颗？', 'solution': '设原有x颗\nx - (x/2 + 1) = 10\nx - x/2 - 1 = 10\nx/2 = 11\nx = 22'}, {'type': 'practice', 'problems': [{'question': '解方程 4x - 3 = 2x + 7', 'options': ['x=5', 'x=2', 'x=5.5', 'x=4'], 'answer': 'x=5'}, {'question': '解方程 (x+3)/2 = (2x-1)/3', 'options': ['x=11', 'x=7', 'x=5', 'x=9'], 'answer': 'x=11'}, {'question': '一个数加上它的一半等于45，这个数是？', 'options': ['30', '22.5', '15', '20'], 'answer': '30'}]}, {'type': 'summary', 'content': '解方程口诀：去分母、去括号、移项变号要记牢。合并同类项，系数化1求出x。'}]}}, {'title': '比例与比例关系', 'lesson_type': 'interactive', 'estimated_minutes': 25, 'sort_order': 2, 'is_published': True, 'content': {'sections': [{'type': 'introduction', 'content': '比例是AMC 8的高频考点。速度、浓度、地图比例尺等问题都涉及比例关系。'}, {'type': 'concept', 'title': '比例基本性质', 'content': '若 a/b = c/d，则 ad = bc（交叉相乘相等）\n正比例：y = kx，一个量增大另一个也增大\n反比例：y = k/x，一个量增大另一个减小\n合分比定理：若a/b = c/d，则(a±b)/b = (c±d)/d'}, {'type': 'example', 'problem': 'AMC 8真题：甲乙两车同时从A、B出发相向而行，甲速60km/h，乙速40km/h。相遇时甲行了180km，求AB距离。', 'solution': '相遇时间 = 180/60 = 3小时\n乙行距离 = 40 × 3 = 120km\nAB = 180 + 120 = 300km'}, {'type': 'example', 'problem': '一幅地图上3cm代表实际45km，地图上AB两点相距7cm，实际距离是多少？', 'solution': '比例：3cm : 45km = 1cm : 15km\n实际距离 = 7 × 15 = 105km'}, {'type': 'practice', 'problems': [{'question': '如果3:5 = x:35，x等于？', 'options': ['21', '7', '15', '25'], 'answer': '21'}, {'question': '甲做一件工作要6天，乙要10天，合作几天完成？', 'options': ['3.75', '8', '4', '5'], 'answer': '3.75'}, {'question': '糖水浓度从10%变成20%，需要蒸发掉原来质量的几分之几？', 'options': ['1/2', '1/3', '2/3', '1/4'], 'answer': '1/2'}]}, {'type': 'summary', 'content': '比例问题三步法：找比例关系 → 列比例式 → 交叉相乘求解。注意正比和反比的区别！'}]}}, {'title': '数列规律', 'lesson_type': 'interactive', 'estimated_minutes': 25, 'sort_order': 3, 'is_published': True, 'content': {'sections': [{'type': 'introduction', 'content': '数列规律题是AMC 8的必考题型。学会观察数列的模式，找到通项公式或求和公式。'}, {'type': 'concept', 'title': '常见数列类型', 'content': '① 等差数列：aₙ = a₁ + (n-1)d，求和 S = n(a₁+aₙ)/2\n② 等比数列：aₙ = a₁ × r^(n-1)，求和 S = a₁(1-r^n)/(1-r)\n③ 平方数列：1, 4, 9, 16, 25, ...，第n项 = n²\n④ 三角形数：1, 3, 6, 10, 15, ...，第n项 = n(n+1)/2\n⑤ 斐波那契：1, 1, 2, 3, 5, 8, ...，每项等于前两项之和'}, {'type': 'example', 'problem': 'AMC 8真题：数列 2, 5, 8, 11, 14, ... 的第100项是多少？', 'solution': '这是等差数列，首项a₁=2，公差d=3\na₁₀₀ = 2 + (100-1)×3 = 2 + 297 = 299'}, {'type': 'example', 'problem': '求 1 + 3 + 5 + 7 + ... + 99 的和', 'solution': '前n个奇数之和 = n²\n1到99共有50个奇数\nS = 50² = 2500'}, {'type': 'practice', 'problems': [{'question': '数列 3, 7, 11, 15, ... 的第20项是？', 'options': ['79', '83', '77', '81'], 'answer': '79'}, {'question': '1+2+3+...+50 = ?', 'options': ['1275', '1250', '1300', '1225'], 'answer': '1275'}, {'question': '斐波那契数列 1,1,2,3,5,8,13,...，第10项是？', 'options': ['55', '34', '89', '44'], 'answer': '55'}]}, {'type': 'summary', 'content': '找规律技巧：①计算相邻项的差（等差？）②计算相邻项的比（等比？）③看是否为平方、三角数等特殊数列'}]}}, {'title': '代数应用题', 'lesson_type': 'interactive', 'estimated_minutes': 25, 'sort_order': 4, 'is_published': True, 'content': {'sections': [{'type': 'introduction', 'content': '应用题是数学与现实的桥梁。AMC 8的应用题需要将文字翻译成数学语言，列方程求解。'}, {'type': 'concept', 'title': '应用题解题策略', 'content': '① 设未知数（通常设所求量为x）\n② 找等量关系（关键句翻译成方程）\n③ 列方程并求解\n④ 检验答案是否合理\n常见类型：行程问题、工程问题、浓度问题、年龄问题、利润问题'}, {'type': 'example', 'problem': 'AMC 8真题：一只蜗牛白天爬3米，晚上滑2米。井深10米，几天能爬出来？', 'solution': '前n-1天净爬升：(3-2)×(n-1) = n-1米\n第n天白天爬3米后出去\nn-1+3 ≥ 10，即n ≥ 8\n所以第8天白天爬出去'}, {'type': 'example', 'problem': '父亲今年36岁，儿子今年8岁，几年后父亲年龄是儿子的3倍？', 'solution': '设x年后：36+x = 3(8+x)\n36+x = 24+3x\n12 = 2x\nx = 6'}, {'type': 'practice', 'problems': [{'question': '小明比小红大5岁，两人年龄之和为35，小明几岁？', 'options': ['20', '15', '18', '25'], 'answer': '20'}, {'question': '商品打八折后售价120元，原价是多少？', 'options': ['150', '144', '96', '160'], 'answer': '150'}, {'question': '鸡兔同笼，共35个头94只脚，鸡有几只？', 'options': ['23', '12', '17', '20'], 'answer': '23'}]}, {'type': 'summary', 'content': '应用题核心：认真读题找关键句→翻译成数学表达式→列方程求解→验证合理性。'}]}}, {'title': '不等式初步', 'lesson_type': 'interactive', 'estimated_minutes': 20, 'sort_order': 5, 'is_published': True, 'content': {'sections': [{'type': 'introduction', 'content': '不等式在AMC 8中常用来确定范围。理解不等式的基本性质和求解方法是解决很多问题的关键。'}, {'type': 'concept', 'title': '不等式性质', 'content': '① 两边加/减同一个数，不等号方向不变\n② 两边乘/除以正数，不等号方向不变\n③ 两边乘/除以负数，不等号方向要反转！\n④ 同向不等式可以相加\n⑤ 同号正数不等式可以相乘'}, {'type': 'example', 'problem': '解不等式：3x - 5 > 2x + 3', 'solution': '3x - 2x > 3 + 5\nx > 8'}, {'type': 'example', 'problem': 'AMC 8真题：满足 2x + 1 < 9 且 3x - 2 > 4 的整数x有几个？', 'solution': '由第一个：2x < 8, x < 4\n由第二个：3x > 6, x > 2\n所以 2 < x < 4\n整数解只有x = 3，共1个'}, {'type': 'practice', 'problems': [{'question': '解不等式 -2x + 6 > 0', 'options': ['x < 3', 'x > 3', 'x < -3', 'x > -3'], 'answer': 'x < 3'}, {'question': '满足 1 ≤ 2x-1 < 7 的整数x有几个？', 'options': ['3', '4', '2', '5'], 'answer': '3'}, {'question': '若 a < 0，则不等式 ax > 3 的解是？', 'options': ['x < 3/a', 'x > 3/a', 'x < -3/a', 'x > -3/a'], 'answer': 'x < 3/a'}]}, {'type': 'summary', 'content': '不等式要点：乘除负数要反转方向！连不等式分别求再取交集。'}]}}]}, {'name': '几何入门', 'description': '学习三角形、四边形、圆的面积与周长，以及角度计算', 'sort_order': 3, 'lessons': [{'title': '三角形基础', 'lesson_type': 'interactive', 'estimated_minutes': 25, 'sort_order': 1, 'is_published': True, 'content': {'sections': [{'type': 'introduction', 'content': '三角形是最基本的几何图形，AMC 8中三角形的面积、角度和性质是必考内容！'}, {'type': 'concept', 'title': '三角形核心公式', 'content': '面积 = ½ × 底 × 高\n内角和 = 180°\n三角形不等式：任意两边之和大于第三边\n等腰三角形两底角相等\n等边三角形每个角60°'}, {'type': 'example', 'problem': 'AMC 8真题：三角形三边分别为5, 12, 13，求面积', 'solution': '检验：5²+12²=25+144=169=13²，这是直角三角形！\n面积 = ½ × 5 × 12 = 30'}, {'type': 'example', 'problem': '等腰三角形一个底角是70°，顶角是多少度？', 'solution': '底角相等：两个底角都是70°\n顶角 = 180° - 70° - 70° = 40°'}, {'type': 'practice', 'problems': [{'question': '三角形三个内角之比为1:2:3，最大角是？', 'options': ['90°', '60°', '120°', '100°'], 'answer': '90°'}, {'question': '底为8cm，高为5cm的三角形面积是？', 'options': ['20cm²', '40cm²', '13cm²', '25cm²'], 'answer': '20cm²'}, {'question': '以下哪组长度能构成三角形？', 'options': ['3,4,8', '5,5,11', '7,7,7', '2,3,6'], 'answer': '7,7,7'}]}, {'type': 'summary', 'content': '三角形三要点：①内角和180° ②面积=½底×高 ③两边之和大于第三边。记住勾股数(3,4,5)(5,12,13)！'}]}}, {'title': '四边形', 'lesson_type': 'interactive', 'estimated_minutes': 25, 'sort_order': 2, 'is_published': True, 'content': {'sections': [{'type': 'introduction', 'content': '四边形包括长方形、正方形、平行四边形、梯形等。掌握各种四边形的面积公式是解题基础。'}, {'type': 'concept', 'title': '四边形面积公式', 'content': '长方形：S = 长 × 宽\n正方形：S = 边长²\n平行四边形：S = 底 × 高\n梯形：S = ½(上底+下底) × 高\n菱形：S = ½ × 对角线₁ × 对角线₂'}, {'type': 'example', 'problem': 'AMC 8真题：一个长方形周长为30，长比宽多3，求面积', 'solution': '设宽为x，则长为x+3\n周长：2(x + x+3) = 30\n4x + 6 = 30, x = 6\n长=9, 宽=6\n面积 = 9 × 6 = 54'}, {'type': 'example', 'problem': '梯形上底4cm，下底10cm，高6cm，求面积', 'solution': 'S = ½(4+10) × 6 = ½ × 14 × 6 = 42cm²'}, {'type': 'practice', 'problems': [{'question': '正方形对角线长10cm，面积是？', 'options': ['50cm²', '100cm²', '25cm²', '75cm²'], 'answer': '50cm²'}, {'question': '平行四边形底12cm，面积72cm²，高是？', 'options': ['6cm', '8cm', '5cm', '10cm'], 'answer': '6cm'}, {'question': '菱形两条对角线分别为8cm和6cm，面积是？', 'options': ['24cm²', '48cm²', '14cm²', '20cm²'], 'answer': '24cm²'}]}, {'type': 'summary', 'content': '四边形面积速记：长宽乘、底高乘、梯形上下底加半乘高、菱形对角线乘积之半。'}]}}, {'title': '圆的周长与面积', 'lesson_type': 'interactive', 'estimated_minutes': 25, 'sort_order': 3, 'is_published': True, 'content': {'sections': [{'type': 'introduction', 'content': '圆是AMC 8几何部分的重要考点。需要熟记圆的周长和面积公式，以及弧长和扇形面积的计算方法。'}, {'type': 'concept', 'title': '圆的公式', 'content': '周长 C = 2πr = πd\n面积 S = πr²\n弧长 l = nπr/180（n为圆心角度数）\n扇形面积 = nπr²/360\n常用近似：π ≈ 3.14159 ≈ 22/7'}, {'type': 'example', 'problem': 'AMC 8真题：一个圆的面积是49π，求它的周长', 'solution': 'πr² = 49π, r² = 49, r = 7\n周长 = 2πr = 14π'}, {'type': 'example', 'problem': '半径为6的圆中，60°扇形的面积是多少？', 'solution': 'S = 60/360 × π × 6² = 1/6 × 36π = 6π'}, {'type': 'practice', 'problems': [{'question': '直径为10的圆的面积是？', 'options': ['25π', '100π', '50π', '10π'], 'answer': '25π'}, {'question': '圆的周长为12π，面积是？', 'options': ['36π', '144π', '24π', '12π'], 'answer': '36π'}, {'question': '90°扇形半径为4，弧长是？', 'options': ['2π', '4π', 'π', '8π'], 'answer': '2π'}]}, {'type': 'summary', 'content': '圆的公式三件套：C=2πr, S=πr², 扇形=圆心角/360×πr²。注意题目给的是直径还是半径！'}]}}, {'title': '面积与体积', 'lesson_type': 'interactive', 'estimated_minutes': 25, 'sort_order': 4, 'is_published': True, 'content': {'sections': [{'type': 'introduction', 'content': 'AMC 8经常考查组合图形的面积和基本立体图形的体积与表面积。掌握拆分法是解决组合图形的关键。'}, {'type': 'concept', 'title': '常见立体体积和表面积', 'content': '长方体：V=长×宽×高, S=2(长×宽+长×高+宽×高)\n正方体：V=a³, S=6a²\n圆柱：V=πr²h, 侧面积=2πrh\n圆锥：V=πr²h/3\n球：V=4πr³/3, S=4πr²'}, {'type': 'example', 'problem': 'AMC 8真题：一个长方体长5cm、宽4cm、高3cm，求体积和表面积', 'solution': '体积 = 5×4×3 = 60cm³\n表面积 = 2(5×4 + 5×3 + 4×3) = 2(20+15+12) = 94cm²'}, {'type': 'example', 'problem': '圆柱底面半径3cm，高10cm，求体积', 'solution': 'V = π × 3² × 10 = 90π cm³'}, {'type': 'practice', 'problems': [{'question': '正方体体积64cm³，表面积是？', 'options': ['96cm²', '64cm²', '48cm²', '128cm²'], 'answer': '96cm²'}, {'question': '圆柱底面直径6cm，高8cm，体积是？', 'options': ['72π', '144π', '36π', '48π'], 'answer': '72π'}, {'question': '长方体棱长之和为120cm，长宽高之比3:2:1，体积是？', 'options': ['810cm³', '648cm³', '486cm³', '324cm³'], 'answer': '810cm³'}]}, {'type': 'summary', 'content': '组合图形面积：拆分成基本图形分别计算。体积公式以底面积×高为主旋律。'}]}}, {'title': '角度与平行线', 'lesson_type': 'interactive', 'estimated_minutes': 20, 'sort_order': 5, 'is_published': True, 'content': {'sections': [{'type': 'introduction', 'content': '平行线与角度的关系是几何推理的基础。掌握同位角、内错角、同旁内角对解题非常重要。'}, {'type': 'concept', 'title': '平行线角度关系', 'content': '两条平行线被第三条线所截：\n同位角相等（对应位置）\n内错角相等（Z形内侧）\n同旁内角互补（和为180°）\n对顶角相等（X形交叉）\n邻补角互补（和为180°）'}, {'type': 'example', 'problem': 'AMC 8真题：平行线l₁, l₂被直线所截，一个同位角为72°，求同旁内角', 'solution': '同位角=72°，则同旁内角=180°-72°=108°'}, {'type': 'example', 'problem': '三角形ABC中，∠A=50°，∠B=65°，延长BC到D，求∠ACD', 'solution': '∠ACD = ∠A + ∠B = 50° + 65° = 115°\n（三角形外角等于不相邻两内角之和）'}, {'type': 'practice', 'problems': [{'question': '两条平行线被截线所截，内错角为78°，同位角是？', 'options': ['78°', '102°', '156°', '90°'], 'answer': '78°'}, {'question': '三角形两个内角分别为55°和75°，第三个角是？', 'options': ['50°', '60°', '40°', '55°'], 'answer': '50°'}, {'question': '正五边形每个内角是？', 'options': ['108°', '120°', '90°', '72°'], 'answer': '108°'}]}, {'type': 'summary', 'content': '角度定理：三角形内角和180°，外角=不相邻两内角之和。平行线产生相等角。正n边形内角=(n-2)×180°/n。'}]}}]}, {'name': '计数与概率', 'description': '掌握排列组合、概率计算、计数原理和统计图表', 'sort_order': 4, 'lessons': [{'title': '计数原理', 'lesson_type': 'interactive', 'estimated_minutes': 25, 'sort_order': 1, 'is_published': True, 'content': {'sections': [{'type': 'introduction', 'content': '计数是组合数学的基础。AMC 8中有大量计数题，掌握加法原理和乘法原理是解决这类问题的关键。'}, {'type': 'concept', 'title': '两大计数原理', 'content': '加法原理（分类）：完成一件事有n类方法，各类分别有m₁,m₂,...,mₙ种，共有m₁+m₂+...+mₙ种\n乘法原理（分步）：完成一件事分n步，各步分别有m₁,m₂,...,mₙ种，共有m₁×m₂×...×mₙ种\n关键区别：互斥用加法，独立用乘法'}, {'type': 'example', 'problem': 'AMC 8真题：从A到B有3条路，从B到C有4条路，从A经B到C有几种走法？', 'solution': '分两步：A→B（3种）× B→C（4种）\n3 × 4 = 12种'}, {'type': 'example', 'problem': '用数字1,2,3,4可以组成多少个没有重复数字的三位数？', 'solution': '百位：4种选择\n十位：3种选择（剩3个数字）\n个位：2种选择\n4 × 3 × 2 = 24个'}, {'type': 'practice', 'problems': [{'question': '5个人排成一排有几种排法？', 'options': ['120', '25', '60', '10'], 'answer': '120'}, {'question': '从4个男生3个女生中各选1人，有几种选法？', 'options': ['12', '7', '21', '10'], 'answer': '12'}, {'question': '书架上有5本不同的书，选2本有几种选法？', 'options': ['10', '20', '25', '5'], 'answer': '10'}]}, {'type': 'summary', 'content': '计数核心：分类用加法，分步用乘法。注意题目是否允许重复。'}]}}, {'title': '排列与组合', 'lesson_type': 'interactive', 'estimated_minutes': 25, 'sort_order': 2, 'is_published': True, 'content': {'sections': [{'type': 'introduction', 'content': '排列组合是计数的系统化方法。排列考虑顺序，组合不考虑顺序。分清这一点是解题关键！'}, {'type': 'concept', 'title': '排列组合公式', 'content': '排列 P(n,r) = n!/(n-r)! — 从n个中选r个排列\n组合 C(n,r) = n!/[r!(n-r)!] — 从n个中选r个组合\n关键性质：C(n,r) = C(n,n-r)\nC(n,0) = C(n,n) = 1'}, {'type': 'example', 'problem': 'AMC 8真题：从6名学生中选3名参加比赛，有几种选法？', 'solution': 'C(6,3) = 6!/(3!×3!) = (6×5×4)/(3×2×1) = 20种'}, {'type': 'example', 'problem': '5人站成一排，其中甲乙必须相邻，有几种站法？', 'solution': '把甲乙看成一个人，4人排列：4! = 24\n甲乙内部排列：2种\n24 × 2 = 48种'}, {'type': 'practice', 'problems': [{'question': 'C(10,2) = ?', 'options': ['45', '90', '20', '50'], 'answer': '45'}, {'question': 'P(5,3) = ?', 'options': ['60', '10', '125', '20'], 'answer': '60'}, {'question': '从8人中选正副队长各1人，有几种选法？', 'options': ['56', '28', '64', '15'], 'answer': '56'}]}, {'type': 'summary', 'content': '排列有顺序P(n,r)，组合无序C(n,r)。小技巧：C(n,r)=C(n,n-r)，可以选较小的r来算。'}]}}, {'title': '概率基础', 'lesson_type': 'interactive', 'estimated_minutes': 25, 'sort_order': 3, 'is_published': True, 'content': {'sections': [{'type': 'introduction', 'content': '概率告诉我们事件发生的可能性大小。AMC 8常考古典概率，掌握基本公式和常见模型即可。'}, {'type': 'concept', 'title': '概率基本公式', 'content': 'P(A) = A事件发生的情况数 / 总情况数\n互补事件：P(不A) = 1 - P(A)\n独立事件：P(A且B) = P(A) × P(B)\n互斥事件：P(A或B) = P(A) + P(B)\n0 ≤ P ≤ 1'}, {'type': 'example', 'problem': 'AMC 8真题：掷两个骰子，点数之和为7的概率是多少？', 'solution': '总和为36种可能\n和为7的组合：(1,6)(2,5)(3,4)(4,3)(5,2)(6,1)共6种\nP = 6/36 = 1/6'}, {'type': 'example', 'problem': '袋中有3红4蓝5白球，随机取一个，取到红球的概率？', 'solution': '总球数 = 3+4+5 = 12\nP(红) = 3/12 = 1/4'}, {'type': 'practice', 'problems': [{'question': '掷一个骰子，点数大于4的概率？', 'options': ['1/3', '1/2', '2/3', '1/6'], 'answer': '1/3'}, {'question': '抛两枚硬币，都是正面的概率？', 'options': ['1/4', '1/2', '1/3', '3/4'], 'answer': '1/4'}, {'question': '从1-10中随机取一个数，是偶数且大于5的概率？', 'options': ['1/5', '1/10', '3/10', '2/5'], 'answer': '1/5'}]}, {'type': 'summary', 'content': '概率 = 有利情况数 ÷ 总情况数。善用互补事件简化计算：P(至少一次) = 1 - P(一次也没有)。'}]}}, {'title': '统计图表', 'lesson_type': 'interactive', 'estimated_minutes': 20, 'sort_order': 4, 'is_published': True, 'content': {'sections': [{'type': 'introduction', 'content': 'AMC 8经常出现统计图表的题目。学会读图、计算平均数、中位数、众数是基本要求。'}, {'type': 'concept', 'title': '统计基础概念', 'content': '平均数 = 数据总和 ÷ 数据个数\n中位数 = 排序后中间的数（偶数个取中间两数平均）\n众数 = 出现次数最多的数\n极差 = 最大值 - 最小值\n加权平均 = Σ(值×权重) / Σ(权重)'}, {'type': 'example', 'problem': 'AMC 8真题：5个学生的分数为 72, 85, 90, 78, 85，求平均数、中位数、众数', 'solution': '平均数 = (72+85+90+78+85)/5 = 410/5 = 82\n排序：72, 78, 85, 85, 90 → 中位数 = 85\n众数 = 85（出现2次）'}, {'type': 'example', 'problem': '甲班30人平均分80，乙班20人平均分90，两班总平均分？', 'solution': '加权平均 = (30×80 + 20×90) / (30+20)\n= (2400 + 1800) / 50 = 4200/50 = 84'}, {'type': 'practice', 'problems': [{'question': '数据 3,5,5,7,9 的中位数是？', 'options': ['5', '5.8', '6', '7'], 'answer': '5'}, {'question': '数据 2,4,4,6,8,10 的众数是？', 'options': ['4', '没有众数', '6', '2和4'], 'answer': '4'}, {'question': '全班平均分85，小明的成绩从80提高到92，全班平均分提高了1分，全班多少人？', 'options': ['12', '10', '8', '15'], 'answer': '12'}]}, {'type': 'summary', 'content': '统计三数：平均数受极端值影响大，中位数抗干扰，众数反映最常见值。读图表先看标题和坐标轴。'}]}}, {'title': '期望值', 'lesson_type': 'interactive', 'estimated_minutes': 20, 'sort_order': 5, 'is_published': True, 'content': {'sections': [{'type': 'introduction', 'content': '期望值是概率论的重要概念。在AMC 8中，期望值问题通常涉及游戏公平性判断和决策。'}, {'type': 'concept', 'title': '期望值公式', 'content': 'E(X) = Σ(xᵢ × P(xᵢ))\n期望值 = 每种结果×其概率 之和\n期望值不一定是可能的结果\n游戏公平 = 期望收益 = 0'}, {'type': 'example', 'problem': 'AMC 8真题：掷骰子，出现1赢得5元，出现6赢得1元，其他情况输2元，期望收益？', 'solution': 'E = (1/6)×5 + (1/6)×1 + (4/6)×(-2)\n= 5/6 + 1/6 - 8/6\n= -2/6 = -1/3 元'}, {'type': 'example', 'problem': '一个袋子里有1个红球和3个蓝球，每次随机取一个放回，取3次期望取到几个红球？', 'solution': '每次取红球概率 = 1/4\nE = 3 × 1/4 = 3/4'}, {'type': 'practice', 'problems': [{'question': '掷骰子期望点数是？', 'options': ['3.5', '3', '4', '3.25'], 'answer': '3.5'}, {'question': '抛硬币，正面赢3元，反面输1元，期望收益？', 'options': ['1', '0', '2', '-1'], 'answer': '1'}, {'question': '彩票2元一张，中奖概率1%，奖金100元，期望收益？', 'options': ['-1', '0', '1', '-2'], 'answer': '-1'}]}, {'type': 'summary', 'content': '期望值 = 各结果×概率的总和。正期望值长期有利，负期望值长期不利。'}]}}]}, {'name': '逻辑推理', 'description': '训练数谜、逻辑判断、奇偶性、数位分析和最值问题', 'sort_order': 5, 'lessons': [{'title': '数谜与数字谜', 'lesson_type': 'interactive', 'estimated_minutes': 25, 'sort_order': 1, 'is_published': True, 'content': {'sections': [{'type': 'introduction', 'content': '数谜题是AMC 8的特色题型。需要通过逻辑推理和数字特性来填出正确的数字。'}, {'type': 'concept', 'title': '解数谜的策略', 'content': '① 从有最多约束的位置入手\n② 利用进位和借位信息\n③ 注意首位不能为0\n④ 利用整除性（被2/3/5/9/11整除的特征）\n⑤ 枚举可能性并排除'}, {'type': 'example', 'problem': 'AMC 8真题：□□ × 3 = □□4，求两位数乘积', 'solution': '个位 × 3 的个位是4\n只有8×3=24满足\n所以个位是8\n验证：18×3=54, 28×3=84, 38×3=114, 48×3=144\n18和28和48都满足'}, {'type': 'example', 'problem': '一个三位数被3除余2，被5除余3，被7除余4，这个数最小是？', 'solution': '被5除余3→个位是3或8\n被3除余2→各数字之和除3余2\n从53开始检查：53÷7=7余4 ✓\n答案是53'}, {'type': 'practice', 'problems': [{'question': '一个数被4除余3，被5除余4，被6除余5，这个数最小是？', 'options': ['59', '23', '119', '35'], 'answer': '59'}, {'question': '三位数abc满足 a+b+c=9 且 abc被9整除，abc最小是？', 'options': ['108', '117', '126', '135'], 'answer': '108'}, {'question': '如果 1A + A1 = BB，A和B各是多少？', 'options': ['A=9,B=1', 'A=8,B=9', 'A=7,B=8', 'A=9,B=0'], 'answer': 'A=9,B=1'}]}, {'type': 'summary', 'content': '数谜解题：找突破口→利用数字特性→逐步推理。注意整除特征：被3整除→数字和被3整除，被9整除→数字和被9整除。'}]}}, {'title': '逻辑判断题', 'lesson_type': 'interactive', 'estimated_minutes': 25, 'sort_order': 2, 'is_published': True, 'content': {'sections': [{'type': 'introduction', 'content': '逻辑判断题考查分析推理能力。AMC 8中常见的真假话问题、条件推理等都需要严密的逻辑思维。'}, {'type': 'concept', 'title': '逻辑推理方法', 'content': '① 假设法：假设某条件为真，推导是否矛盾\n② 排除法：逐一排除不可能的情况\n③ 反证法：假设结论不成立，推出矛盾\n④ 列表法：画表格整理条件\n⑤ 真假话问题：只有一人说真话时，说真话的人的否定条件为假'}, {'type': 'example', 'problem': 'AMC 8真题：甲说"乙在说谎"，乙说"丙在说谎"，丙说"甲和乙都在说谎"，谁在说真话？', 'solution': '假设丙说真话→甲乙都说谎→甲说"乙说谎"是假话→乙说真话→矛盾！\n所以丙说谎→乙说"丙说谎"是真话→乙说真话→甲说"乙说谎"是假话→甲说谎\n结论：乙说真话，甲丙说谎'}, {'type': 'example', 'problem': '三个盒子分别标着"苹果""橘子""苹果和橘子"，但所有标签都贴错了。从"苹果和橘子"盒子里取出一个水果，是苹果，请确定各盒子的正确标签。', 'solution': '"苹果和橘子"标签错→里面不是混合\n取出苹果→这个盒子只有苹果\n"橘子"标签也错→不是橘子→是混合\n"苹果"标签也错→不是苹果→是橘子\n答案：标"苹果和橘子"→苹果，标"橘子"→混合，标"苹果"→橘子'}, {'type': 'practice', 'problems': [{'question': 'A说B是骑士，B说A和C都是骑士。已知骑士说真话、无赖说假话，谁是骑士？', 'options': ['A', 'B', 'A和B', '都不是'], 'answer': 'A'}, {'question': '5个队循环赛，每两队赛一场，已知A赛了4场，B赛了3场，C赛了2场，D赛了1场，E赛了几场？', 'options': ['2', '3', '4', '1'], 'answer': '2'}, {'question': '三扇门，一扇后面有奖品。你选了门1，主持人打开门3（没有奖品），换到门2中奖概率？', 'options': ['2/3', '1/2', '1/3', '3/4'], 'answer': '2/3'}]}, {'type': 'summary', 'content': '逻辑推理：假设→推导→检验是否矛盾。真假话问题从"只有一人说真话"的条件入手。'}]}}, {'title': '奇偶性分析', 'lesson_type': 'interactive', 'estimated_minutes': 20, 'sort_order': 3, 'is_published': True, 'content': {'sections': [{'type': 'introduction', 'content': '奇偶性是数学竞赛中的重要工具。利用奇偶性可以快速排除不可能的情况，缩小答案范围。'}, {'type': 'concept', 'title': '奇偶性规则', 'content': '奇+奇=偶, 偶+偶=偶, 奇+偶=奇\n奇×奇=奇, 偶×任何=偶\n连续两个整数之积必为偶\nn个整数之和为奇→至少有奇数个奇数\nn²的奇偶性与n相同'}, {'type': 'example', 'problem': 'AMC 8真题：能否将1到10这10个数分成两组，使两组和相等？', 'solution': '总和 = 55（奇数）\n每组需要和 = 55/2 = 27.5（不是整数）\n不可能！因为奇数不能平分为两个相等的整数'}, {'type': 'example', 'problem': '1²+2²+3²+...+100² 的结果是奇数还是偶数？', 'solution': '1²到100²中有50个奇数的平方（奇）和50个偶数的平方（偶）\n50个奇数之和 = 偶数\n50个偶数之和 = 偶数\n总和 = 偶数'}, {'type': 'practice', 'problems': [{'question': '三个连续奇数的和一定是？', 'options': ['3的倍数', '奇数', '偶数', '6的倍数'], 'answer': '3的倍数'}, {'question': '1+2+3+...+99 的结果是？', 'options': ['奇数', '偶数', '不能确定', '完全平方数'], 'answer': '奇数'}, {'question': '两个质数之和为奇数，这两个质数是？', 'options': ['2和另一个奇质数', '两个奇质数', '两个偶质数', '不可能'], 'answer': '2和另一个奇质数'}]}, {'type': 'summary', 'content': '奇偶性是快速判断利器：和的奇偶看奇数个数，积的奇偶看有没有偶数因子。'}]}}, {'title': '数位分析', 'lesson_type': 'interactive', 'estimated_minutes': 20, 'sort_order': 4, 'is_published': True, 'content': {'sections': [{'type': 'introduction', 'content': '数位分析是AMC 8的经典题型。理解数的位值原理，掌握数字操作的技巧。'}, {'type': 'concept', 'title': '数位基本性质', 'content': '一个数 = 各位数字 × 对应位值的和\n如 abc = 100a + 10b + c\n交换数字：bac = 100b + 10a + c\n一个数被9整除 ↔ 数字和被9整除\n一个数被11整除 ↔ 奇数位数字和与偶数位数字和之差被11整除'}, {'type': 'example', 'problem': 'AMC 8真题：一个两位数，十位数字是个位数字的2倍，两个数字之和为9，这个数是？', 'solution': '设个位为x，十位为2x\n2x + x = 9, x = 3\n十位=6，个位=3\n这个数是63'}, {'type': 'example', 'problem': '一个三位数，交换百位和个位后比原数小495，这样的三位数有多少个？', 'solution': '设原数=100a+10b+c，新数=100c+10b+a\n差=99(a-c)=495\na-c=5\na可取6,7,8,9（对应c=1,2,3,4）\nb可取0-9共10个\n4×10=40个'}, {'type': 'practice', 'problems': [{'question': '一个两位数的数字之和为11，交换两个数字后比原数大27，原数是？', 'options': ['47', '74', '38', '56'], 'answer': '47'}, {'question': '用1,2,3,4能组成多少个没有重复数字的四位偶数？', 'options': ['12', '6', '24', '8'], 'answer': '12'}, {'question': '一个数各位数字之和为15，这个数最小是？', 'options': ['69', '78', '159', '87'], 'answer': '69'}]}, {'type': 'summary', 'content': '数位分析：用位值展开，注意进位。数字和特征判断整除性。交换数字后用代数方法表示差。'}]}}, {'title': '最值问题', 'lesson_type': 'interactive', 'estimated_minutes': 25, 'sort_order': 5, 'is_published': True, 'content': {'sections': [{'type': 'introduction', 'content': '最值问题要求在给定条件下找到最大或最小值。AMC 8常考面积最值、数字最值等。'}, {'type': 'concept', 'title': '求最值的方法', 'content': '① 不等式法：利用基本不等式 a+b≥2√(ab)\n② 配方法：二次函数 y=ax²+bx+c，顶点处取最值\n③ 极端原理：考虑边界情况\n④ 枚举法：在有限范围内逐一检验\n⑤ 对称法：当各量相等时，积或和往往取最值'}, {'type': 'example', 'problem': 'AMC 8真题：周长为20的长方形，面积最大是多少？', 'solution': '设长x，宽10-x（周长20→长+宽=10）\n面积 = x(10-x) = 10x - x²\n当x=5时最大，最大面积 = 25\n（正方形时面积最大）'}, {'type': 'example', 'problem': '用1,2,3,4组成两个两位数，使它们的乘积最大', 'solution': '要使乘积最大，大数放十位\n十位取4和3，个位取2和1\n41×32=1312, 42×31=1302\n31×42=1302, 32×41=1312\n最大乘积为1312'}, {'type': 'practice', 'problems': [{'question': '周长为24的长方形最大面积是？', 'options': ['36', '24', '48', '32'], 'answer': '36'}, {'question': '两个正整数之和为20，乘积最大是？', 'options': ['100', '99', '96', '81'], 'answer': '100'}, {'question': '用2,3,5,7组成最大两位数×最小两位数，结果是？', 'options': ['75×23=1725', '73×25=1825', '53×27=1431', '57×23=1311'], 'answer': '75×23=1725'}]}, {'type': 'summary', 'content': '最值问题策略：和定积最大→各量相等时；积定和最小→各量相等时。二次函数顶点公式x=-b/(2a)。'}]}}]}, {'name': '综合实战', 'description': '解题策略、时间管理、模拟测试和真题演练', 'sort_order': 6, 'lessons': [{'title': 'AMC 8 解题策略总览', 'lesson_type': 'interactive', 'estimated_minutes': 25, 'sort_order': 1, 'is_published': True, 'content': {'sections': [{'type': 'introduction', 'content': 'AMC 8 共25题，40分钟。平均每题不到2分钟，策略和技巧至关重要！'}, {'type': 'concept', 'title': 'AMC 8 应试策略', 'content': '① 选择题策略：排除法 + 特殊值法 + 代入验证\n② 时间分配：前10题10分钟，中间10题20分钟，最后5题10分钟\n③ 蒙题技巧：答案通常均匀分布，排除后从剩余选\n④ 画图辅助：几何题一定要画图标注\n⑤ 逆向思考：从选项反推\n⑥ 特殊情况：代入1, 0, -1等特殊值检验'}, {'type': 'example', 'problem': 'AMC 8策略题：如果 x² - 5x + 6 = 0，求 x³ - 5x² + 6x + 1 的值', 'solution': '由方程得 x² = 5x - 6\n代入：x³ = x·x² = x(5x-6) = 5x² - 6x\nx³ - 5x² + 6x = (5x²-6x) - 5x² + 6x = 0\n原式 = 0 + 1 = 1'}, {'type': 'example', 'problem': '选择题技巧：一个正整数n满足n²的个位数字和n的个位数字相同，这样的n在1到100之间有多少个？', 'solution': '枚举个位数字：0²=0✓, 1²=1✓, 2²=4✗, 3²=9✗, 4²=6✗\n5²=5✓, 6²=6✓, 7²=9✗, 8²=4✗, 9²=1✗\n满足的有0,1,5,6\n1-100中个位为0,1,5,6的各有10个，共40个'}, {'type': 'practice', 'problems': [{'question': 'AMC 8共25题，答对得1分，不答得0分，答错不扣分。小明答了20题对了15题，他的得分是？', 'options': ['15', '20', '18', '17'], 'answer': '15'}, {'question': '方程 |x-3| + |x-7| = 6 的解有多少个？', 'options': ['无数个', '2个', '1个', '0个'], 'answer': '无数个'}, {'question': '选择正确答案的策略：先排除确定错误的选项，剩下的在剩余选项中猜，期望得分？', 'options': ['比随机猜高', '和随机猜一样', '比随机猜低', '取决于排除数量'], 'answer': '比随机猜高'}]}, {'type': 'summary', 'content': 'AMC 8策略核心：速度+准确率并重。前15题要稳拿，后10题靠技巧。排除法是最强武器！'}]}}, {'title': '时间管理与答题节奏', 'lesson_type': 'interactive', 'estimated_minutes': 20, 'sort_order': 2, 'is_published': True, 'content': {'sections': [{'type': 'introduction', 'content': '40分钟25题意味着平均每题96秒。合理分配时间、学会放弃难题是拿高分的关键。'}, {'type': 'concept', 'title': '时间管理策略', 'content': '① 三遍做题法：\n  第一遍（15分钟）：快速做完简单题（约1-15题）\n  第二遍（15分钟）：解决中等题（约16-22题）\n  第三遍（10分钟）：挑战难题（约23-25题）\n② 单题限时：简单题1分钟，中等题2分钟，难题3分钟\n③ 超时策略：超过3分钟没思路就跳过\n④ 检查：最后5分钟检查前15题'}, {'type': 'example', 'problem': '模拟场景：你做了10题用了12分钟，第11题已经想了3分钟还没思路，怎么办？', 'solution': '最佳策略：先跳过第11题\n分析：10题12分钟，比计划稍快，状态不错\n先把12-20题做完（预计15分钟）\n然后回来做11题和剩余的（预计13分钟）\n最后检查（5分钟）'}, {'type': 'example', 'problem': '考试结束前5分钟还有3题没做（23,24,25题），怎么办？', 'solution': '策略：不要3题都空着\n快速看题，选最有把握的1-2题尝试\n剩下的根据已选答案分布来猜\n如果已选答案中A很少，优先猜A\n确保不空题——猜也有20-25%正确率'}, {'type': 'practice', 'problems': [{'question': 'AMC 8中，建议花多长时间在前10题？', 'options': ['10分钟', '15分钟', '20分钟', '5分钟'], 'answer': '10分钟'}, {'question': '一道题想了4分钟还没思路，最好怎么办？', 'options': ['继续想', '跳过做后面的', '随便选一个', '放弃考试'], 'answer': '跳过做后面的'}, {'question': '最后2分钟还有4题没做，最佳策略？', 'options': ['都空着', '快速猜答案确保不空题', '认真做1题', '检查已做的'], 'answer': '快速猜答案确保不空题'}]}, {'type': 'summary', 'content': '时间管理口诀：先易后难、能做就做、不会就跳、最后再猜、确保不空。'}]}}, {'title': '常见陷阱与错误分析', 'lesson_type': 'interactive', 'estimated_minutes': 20, 'sort_order': 3, 'is_published': True, 'content': {'sections': [{'type': 'introduction', 'content': '了解AMC 8的常见陷阱可以帮助你避免不必要的失分。'}, {'type': 'concept', 'title': 'AMC 8十大常见陷阱', 'content': '① 未注意"不同"与"可以相同"的区别\n② 计算时看错数字\n③ 几何题未注意单位\n④ 混淆"增加"和"增加到"\n⑤ 忘记考虑所有情况\n⑥ 概率题分母总数算错\n⑦ 图形旋转翻转后当成原图\n⑧ 正负号搞错\n⑨ 混淆周长和面积\n⑩ 未读完题目就动笔'}, {'type': 'example', 'problem': '陷阱题：一个圆的半径增加50%，面积增加了百分之几？', 'solution': '易错：回答50%\n正确：新半径=1.5r，新面积=π(1.5r)²=2.25πr²\n面积增加了125%'}, {'type': 'example', 'problem': '陷阱题：将长方形纸对折3次后剪去一个角，展开后有多少个洞？', 'solution': '对折3次→8层\n剪去一个角→每层都剪了→展开后8个洞\n（不是3个洞！）'}, {'type': 'practice', 'problems': [{'question': '价格先涨10%再降10%，最终比原价？', 'options': ['低', '高', '不变', '不确定'], 'answer': '低'}, {'question': '1到100中"3"出现了多少次？', 'options': ['20', '19', '10', '11'], 'answer': '20'}, {'question': '三角形三边为3,4,5，斜边上的高是？', 'options': ['2.4', '3', '4', '2.5'], 'answer': '2.4'}]}, {'type': 'summary', 'content': '防陷阱：读题两遍、注意关键词、检查单位、验证答案合理性。'}]}}, {'title': 'AMC 8 模拟测试', 'lesson_type': 'interactive', 'estimated_minutes': 30, 'sort_order': 4, 'is_published': True, 'content': {'sections': [{'type': 'introduction', 'content': '模拟测试是检验学习成果的最佳方式。这节课我们来做一套精简版AMC 8模拟题。'}, {'type': 'concept', 'title': '模拟测试说明', 'content': '本测试包含10道精选AMC 8风格题目，涵盖数的运算、几何、计数、概率和逻辑推理。\n建议用时：15分钟\n目标：至少答对7题'}, {'type': 'example', 'problem': '第1题：计算 (1 + 2 + 3 + ... + 20) - (2 + 4 + 6 + ... + 20) 的值', 'solution': '原式 = 所有数之和 - 偶数之和 = 奇数之和\n所有数之和 = 20×21/2 = 210\n偶数之和 = 2+4+...+20 = 2(1+2+...+10) = 2×55 = 110\n奇数之和 = 210 - 110 = 100'}, {'type': 'example', 'problem': '第5题：一个班级有30名学生，其中18人选了数学课，15人选了英语课，10人两门都选了。有多少人两门都没选？', 'solution': '选了至少一门 = 18 + 15 - 10 = 23人\n两门都没选 = 30 - 23 = 7人\n（容斥原理）'}, {'type': 'practice', 'problems': [{'question': '模拟1: 一个数的3倍减5等于16，这个数是？', 'options': ['7', '6', '8', '5'], 'answer': '7'}, {'question': '模拟2: 长方形周长36cm，长是宽的2倍，面积是？', 'options': ['72cm²', '48cm²', '96cm²', '64cm²'], 'answer': '72cm²'}, {'question': '模拟3: 从5双不同的鞋中随机取4只，至少有一双配对的概率？', 'options': ['大于50%', '等于50%', '小于50%', '等于100%'], 'answer': '大于50%'}]}, {'type': 'summary', 'content': '模拟测试要点：控制时间、先易后难、注意审题、不留空白。'}]}}, {'title': '真题演练精选', 'lesson_type': 'interactive', 'estimated_minutes': 30, 'sort_order': 5, 'is_published': True, 'content': {'sections': [{'type': 'introduction', 'content': '最后一课！我们精选了AMC 8历年真题中的经典题目来综合训练。'}, {'type': 'concept', 'title': '真题演练要点', 'content': '① 认真审题，标记关键信息\n② 选择合适的方法（代数/几何/计数/逻辑）\n③ 验证答案合理性\n④ 总结每道题的考点和解法'}, {'type': 'example', 'problem': '2022 AMC 8精选：一个矩形被分成5×7的小方格，从左下角走到右上角，只能向右或向上走，共有几种走法？', 'solution': '需要向右走6步，向上走4步，共10步\n从10步中选6步向右：C(10,6) = C(10,4)\n= 10!/(4!×6!) = (10×9×8×7)/(4×3×2×1) = 210种'}, {'type': 'example', 'problem': '正方形ABCD边长为6，E是BC中点，求AE的长度', 'solution': '设坐标系：A=(0,0), B=(6,0), C=(6,6), D=(0,6)\nE=(6,3)\nAE = √(36+9) = √45 = 3√5'}, {'type': 'practice', 'problems': [{'question': '真题1: 三个连续偶数的平方和为200，这三个数是？', 'options': ['6,8,10', '4,6,8', '8,10,12', '2,4,6'], 'answer': '6,8,10'}, {'question': '真题2: 从1到100中，既不是3的倍数也不是5的倍数的数有几个？', 'options': ['53', '47', '60', '40'], 'answer': '53'}, {'question': '真题3: 正六边形边长为1，面积是？', 'options': ['3√3/2', '6√3', '3', '2√3'], 'answer': '3√3/2'}]}, {'type': 'summary', 'content': '恭喜完成AMC 8基础课程！记住：数学竞赛的秘诀是大量练习+总结规律+保持信心。继续加油！'}]}}]}]
